{
  "name": "temporal-hello-world-ts",
  "version": "1.0.0",
  "description": "Hello World Temporal Workflow in TypeScript",
  "main": "dist/client.js",
  "scripts": {
    "build": "tsc --build",
    "start": "npm run build && node dist/start.js"
  },
  "dependencies": {
    "@temporalio/activity": "^1.11.7",
    "@temporalio/client": "^1.11.7",
    "@temporalio/worker": "^1.11.7",
    "@temporalio/workflow": "^1.11.7"
  },
  "devDependencies": {
    "typescript": "^5.4.5",
    "@types/node": "^20.0.0"
  }
}

export async function greet(name: string): Promise<string> {
  return `Hello, ${name}!`;
}

import { proxyActivities } from '@temporalio/workflow';
import type * as activities from './activities';

const { greet } = proxyActivities<typeof activities>({
  startToCloseTimeout: '10 seconds',
});

export async function HelloWorkflow(name: string): Promise<string> {
  return await greet(name);
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities';
import path from 'path';

async function run(): Promise<void> {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  const worker = await Worker.create({
    connection,
    namespace,
    taskQueue: 'hello-world-ts',
    workflowsPath: path.join(__dirname, 'workflows'),
    activities,
  });

  console.log('Worker started, polling task queue: hello-world-ts');
  await worker.run();
}

run().catch((err) => {
  console.error('Worker failed:', err);
  process.exit(1);
});

import { Connection, Client } from '@temporalio/client';
import { HelloWorkflow } from './workflows';

async function run(): Promise<void> {
  const apiKey = process.env.TEMPORAL_API_KEY;
  const address = process.env.TEMPORAL_ADDRESS;
  const namespace = process.env.TEMPORAL_NAMESPACE;
  const runId = process.env.ZEALT_RUN_ID ?? 'local';

  if (!apiKey || !address || !namespace) {
    throw new Error(
      'Missing required environment variables: TEMPORAL_API_KEY, TEMPORAL_ADDRESS, TEMPORAL_NAMESPACE'
    );
  }

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({
    connection,
    namespace,
  });

  const workflowId = `hello-wf-${runId}`;
  console.log(`Starting HelloWorkflow with ID: ${workflowId}`);

  const result = await client.workflow.execute(HelloWorkflow, {
    taskQueue: 'hello-world-ts',
    workflowId,
    args: ['Temporal'],
  });

  console.log(result);

  await connection.close();
}

run().catch((err) => {
  console.error('Client failed:', err);
  process.exit(1);
});

import { spawn } from 'child_process';
import path from 'path';

async function main(): Promise<void> {
  // Spawn the worker as a background child process
  const workerProcess = spawn(
    process.execPath,
    [path.join(__dirname, 'worker.js')],
    {
      env: process.env,
      stdio: ['ignore', 'pipe', 'pipe'],
    }
  );

  workerProcess.stdout?.on('data', (data: Buffer) => {
    process.stdout.write(`[worker] ${data}`);
  });
  workerProcess.stderr?.on('data', (data: Buffer) => {
    process.stderr.write(`[worker] ${data}`);
  });

  // Give the worker a moment to connect before starting the client
  await new Promise((resolve) => setTimeout(resolve, 3000));

  // Run the client inline
  try {
    await import('./client');
  } catch (err) {
    console.error('Client error:', err);
    workerProcess.kill('SIGTERM');
    process.exit(1);
  }

  // Terminate the worker now that the workflow has completed
  workerProcess.kill('SIGTERM');

  // Give a moment for graceful shutdown
  await new Promise((resolve) => setTimeout(resolve, 1000));

  process.exit(0);
}

main().catch((err) => {
  console.error('Fatal error:', err);
  process.exit(1);
});

